var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하하하! 드디어 찾았다!","JPN":"ハハハハ！　やっと見つけた！","ENG":"Hahahaha! I finally found you!","TWN":"哈哈哈！終於找到你們了！"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 얼터너티브 실험체, 시작형!","JPN":"リプレイサー・オルタナティブ実験体の試作型！","ENG":"The preliminary form of the Replacer Alternative Type...!","TWN":"克隆可替代實驗體，試作型！"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"크윽......! 뭐야!!","JPN":"くっ…！　何だよ！！","ENG":"Whoa! What the heck!","TWN":"唔……！什麼！"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저건.......","JPN":"あれは……","ENG":"Is that...","TWN":"那是………"},"stage":{"bg":"BLACK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......참 반갑지 않은 얼굴이네.","JPN":"……歓迎できない奴のお出ましね。","ENG":"That's the last face I wanted to see today.","TWN":"……還真是一張不受歡迎的臉啊。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 우릴 그 이름으로 부르지 말아 줬으면 좋겠는데?","JPN":"それと私たちをそんな風に呼ばないでくれる？","ENG":"And can you stop calling us that?","TWN":"還有，可以請妳不要用那個名字稱呼我們嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우린 알트 소대다.","JPN":"私たちはアルト小隊よ。","ENG":"We're ALT Squad now.","TWN":"我們是阿爾特小隊。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하? 웃기려고 한 말이라면 칭찬해 주지.","JPN":"は？　笑わせようとしてるなら、褒めてやるよ。","ENG":"Ha? Was that supposed to be a joke? Because that was hilarious.","TWN":"哈？如果妳是在搞笑的話，那還真該稱讚一下妳的幽默感。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"만약 진심이라면 도망쳐서 숨어 지내는 동안 머리가 이상해졌다고 밖에는 생각할 수가 없겠는데?","JPN":"もし本気なら、逃亡中に頭がおかしくなったとしか考えられねえな。","ENG":"Or did your brains get all messed up while you were living in hiding?","TWN":"但如果妳是真心這麼說的話，那在這段逃亡的期間，你們的腦袋大概出問題了吧。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"이 멍청한 미완성품들아. 네놈들에게 이름 같은 건 없어.","JPN":"この間抜けな未完成品ども。お前らに名前なんてねえぞ。","ENG":"You're nothing but unfinished products... You don't have a name.","TWN":"你們這些愚蠢的未完成品，才沒有什麼名字。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그런 걸 가질 자격도 없고.","JPN":"そんなものを持つ資格なんてないからな。","ENG":"You're not worthy of one.","TWN":"你們不配擁有那種東西。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"네놈들은 그냥 우리의 대의를 이루기 위한 부품일 뿐이야.","JPN":"お前らはただ我々の大義を成し遂げるための部品に過ぎないんだよ。","ENG":"You're insignificant parts made for the sole purpose of achieving our cause.","TWN":"你們這些傢伙，只不過是實現我們大義的一個小零件而已。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"몇 번이나 교훈을 줬던 것 같은데, 벌써 다 잊어버렸나?","JPN":"何回も注意したのに、もうすべて忘れちまったのか。","ENG":"You've been taught this many times before. Do I really have to remind you?","TWN":"都吃了多少次教訓，難道全都忘了嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"......누가 네놈들의 부품이냐! 이 노출증 환자가?!","JPN":"……誰がお前らの部品だ！　この露出狂が！","ENG":"Who are you calling \\"parts\\"! You half-naked skank!","TWN":"……誰是你們的零件啊！妳這個暴露狂患者？！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"맞아.","JPN":"まったくね。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우린 누군가의 부품이나 실험체 같은 게 아니야.","JPN":"私たちは誰かの部品や実験体なんかじゃない。","ENG":"We're not just some parts, or your test subjects.","TWN":"我們不是某人的零部件或實驗體。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우린 각자 의지를 가진 엄연한 인간이야.","JPN":"私たちはそれぞれの意志を持つ厳然たる人間よ。","ENG":"We're sentient human individuals.","TWN":"我們是有獨立意志、有尊嚴的人。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......너 같은 살인기계는 영원히 이해하지 못하겠지만.","JPN":"……あなたのような殺人マシンには永遠に理解できないでしょうけど。","ENG":"Although I doubt a killing machine like you would ever understand...","TWN":"……像妳這樣的殺人機器，是永遠不會理解的吧。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하아...... 여긴 주제 파악을 못하는 녀석들이 너무 많군.","JPN":"はあ……こりゃ、身の程知らずな奴が多すぎるな。","ENG":"Dear me... Why are there so many fools who don't know their place here?","TWN":"唉……這裡抓不住重點的傢伙實在太多了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"뭐, 그렇다고 해 두지, 얼터너티브 실험체.","JPN":"まあ、そういうことにしておくか、オルタナティブ実験体。","ENG":"Have it your way, alternative test subjects.","TWN":"不然這樣說吧，可替代實驗體。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"어차피 추출기에 다시 들어가면 이름 따위는 다 잊어버리게 될 테니까.","JPN":"どうせ抽出器に戻れば、名前なんて全部忘れちまうからな。","ENG":"You'll forget you even had a name once I put you in the extractor again anyway.","TWN":"反正你們只要再進入萃取器裡，名字什麼的全部都會被忘掉。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......누가 추출기에 들어간대?!","JPN":"……誰が抽出器に入るって！？","ENG":"...No one's going in the extractor!","TWN":"……誰要再進去萃取器啊！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"난 죽는 한이 있어도 거기에 다시 들어갈 생각 따윈 없거든!","JPN":"そこにまた入るなんて、死んでもイヤだね！","ENG":"I'd rather die than go back there!","TWN":"我死也不會再進去了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장......","JPN":"た、隊長……","ENG":"C-Cap...","TWN":"隊、隊長……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"시끄럽군. 이래서 부품 따위에게 팔다리를 달아 놓으니까 문제라는 거야.","JPN":"うるせえ。部品に手足なんかつけるから、こんな面倒なことになるんだ。","ENG":"Ugh, will you ever shut up? This is exactly why I said we shouldn't give you fools limbs.","TWN":"吵死了。給你們這些零件裝上手腳後，果然就是會發生問題。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"자...... 그동안 쓸데없이 도망쳐 다니면서 우릴 귀찮게 한 대가를 치를 시간이 왔다.","JPN":"さあ……これまで無駄に逃げ回ってアタシらを煩わせやがった代償を払う時間だ。","ENG":"Now... It's time for you to pay for running away and wasting our precious time.","TWN":"現在……你們無謂的逃亡給我們帶來了這麼多麻煩，是時候該讓你們付出代價了。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"각오는 됐겠지? 얼터너티브 실험체들아.","JPN":"覚悟はできてるよな？　オルタナティブ実験体ども。","ENG":"Are you ready? Alternative Types...","TWN":"做好心理準備了吧？ 可替代性實驗體。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"내게 이 고생을 시킨 만큼 아주 신경 써서 귀여워해 주지.","JPN":"アタシに散々苦労をさせた分、特別に可愛がってやるよ。","ENG":"I'll make you pay for every single second you wasted.","TWN":"竟然讓我花了這麼多力氣，我會好好疼愛你們的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"......너희들이 지를 비명이 벌써부터 기대되는군.","JPN":"……お前らの悲鳴が、今から楽しみでたまらねえぜ。","ENG":"I can't wait to hear you scream in terror...","TWN":"……我會期待你們的慘叫的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대장...... 나 무, 무서워.......","JPN":"隊長……私、こわいです……","ENG":"Cap... I-I'm scared...","TWN":"隊長……我、我好害怕……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"걱정 마. 언젠가는 이런 날이 올 줄 알고 있었잖아?","JPN":"心配しないで。いつかはこんな日が来るとわかってたでしょ？","ENG":"Don't worry. We all knew this day was coming, right?","TWN":"別擔心，我們都知道這一天總會來的，不是嗎？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"오늘을 위해서 우리가 힘을 길러 온 거야.","JPN":"この日のために、私たちは力をつけてきたの。","ENG":"We've been building our strength for this very day.","TWN":"為了這一天，我們不斷地累積實力。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......우린 지지 않아!","JPN":"……私たちは決して負けない！","ENG":"We're not going to lose!","TWN":"……我們是不會輸的！！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};